import React from 'react';
import { GitHubRepo } from '../../types/github';
import { Box, Typography, Paper, LinearProgress, Tooltip } from '@mui/material';

interface HealthScoreProps {
  repo: GitHubRepo;
}

const calculateScore = (repo: GitHubRepo): { score: number; factors: Record<string, { value: number; weight: number }> } => {
  const factors = {
    stars: { value: Math.min(repo.stargazers_count / 1000, 1) * 100, weight: 0.3 },
    forks: { value: Math.min(repo.forks_count / 500, 1) * 100, weight: 0.15 },
    watchers: { value: Math.min(repo.watchers_count / 1000, 1) * 100, weight: 0.1 },
    openIssues: { value: Math.max(1 - repo.open_issues_count / (repo.stargazers_count > 0 ? repo.stargazers_count : 1), 0) * 100, weight: 0.2 },
    recency: { 
      value: Math.max((new Date().getTime() - new Date(repo.pushed_at).getTime()) / (365 * 24 * 60 * 60 * 1000) < 1 ? 100 : 0, 0), 
      weight: 0.25 
    },
  };

  let totalScore = 0;
  for (const key in factors) {
    const factor = factors[key as keyof typeof factors];
    totalScore += factor.value * factor.weight;
  }

  return { score: Math.round(totalScore), factors };
};

const HealthScore: React.FC<HealthScoreProps> = ({ repo }) => {
  const { score, factors } = calculateScore(repo);

  const getScoreColor = (value: number) => {
    if (value > 75) return 'success';
    if (value > 40) return 'warning';
    return 'error';
  };

  return (
    <Paper sx={{ p: 2, height: '100%' }}>
      <Typography variant="h6" gutterBottom>Repository Health</Typography>
      <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
        <Typography variant="h2" component="span" color={`${getScoreColor(score)}.main`} sx={{ mr: 2 }}>
          {score}
        </Typography>
        <Box sx={{ width: '100%' }}>
          <Tooltip title={`Score: ${score}/100`}>
            <LinearProgress variant="determinate" value={score} color={getScoreColor(score)} sx={{ height: 10, borderRadius: 5 }} />
          </Tooltip>
        </Box>
      </Box>
      <Box>
        <Typography variant="subtitle2">Contributing Factors:</Typography>
        <ul>
          <li>Stars: {factors.stars.value.toFixed(0)}/100</li>
          <li>Forks: {factors.forks.value.toFixed(0)}/100</li>
          <li>Watchers: {factors.watchers.value.toFixed(0)}/100</li>
          <li>Issue Health: {factors.openIssues.value.toFixed(0)}/100</li>
          <li>Recency (Updated in last year): {factors.recency.value > 0 ? 'Yes' : 'No'}</li>
        </ul>
      </Box>
    </Paper>
  );
};

export default HealthScore;
