import React, { useEffect, useState } from 'react';
import { Paper, Typography, Box, Button, CircularProgress, Table, TableBody, TableCell, TableContainer, TableHead, TableRow, Alert } from '@mui/material';
import { getRepositoryContent } from '../../services/api';
import { Buffer } from 'buffer';

interface SecretDetectionProps {
  owner: string;
  repoName: string;
}

// Basic regex patterns for secret detection
const secretPatterns: { [key: string]: RegExp } = {
  'AWS Access Key ID': /AKIA[0-9A-Z]{16}/g,
  'GitHub Token': /ghp_[0-9a-zA-Z]{36}/g,
  'Generic API Key': /[Aa][Pp][Ii]_?[Kk][Ee][Yy]\s*[:=]\s*['"]?([a-zA-Z0-9-_.]{16,})['"]?/g,
  'Private Key': /-----BEGIN (RSA|EC|OPENSSH) PRIVATE KEY-----/g,
};

const filesToScan = ['.env', 'config.json', 'credentials.json', 'settings.py', 'database.yml'];

interface FoundSecret {
  file: string;
  type: string;
  snippet: string;
}

const SecretDetection: React.FC<SecretDetectionProps> = ({ owner, repoName }) => {
  const [secrets, setSecrets] = useState<FoundSecret[]>([]);
  const [loading, setLoading] = useState(false);
  const [scanned, setScanned] = useState(false);

  const handleScan = async () => {
    setLoading(true);
    setScanned(true);
    setSecrets([]);
    
    try {
      const rootContent = await getRepositoryContent(owner, repoName);
      const interestingFiles = rootContent.filter((item: any) => filesToScan.includes(item.name));

      const found: FoundSecret[] = [];
      for (const file of interestingFiles) {
        const fileContentResponse = await getRepositoryContent(owner, repoName, file.path);
        const fileContent = Buffer.from(fileContentResponse.content, 'base64').toString('utf8');
        
        for (const type in secretPatterns) {
          const matches = fileContent.match(secretPatterns[type]);
          if (matches) {
            matches.forEach(match => {
              found.push({
                file: file.path,
                type: type,
                snippet: `...${match.substring(0, 5)}...${match.substring(match.length - 5)}...` // Masked
              });
            });
          }
        }
      }
      setSecrets(found);
    } catch (error) {
      console.error("Error scanning for secrets:", error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Paper sx={{ p: 2, mt: 2 }}>
      <Typography variant="h6" gutterBottom>Secret Detection</Typography>
      <Alert severity="info" sx={{ mb: 2 }}>
        This performs a basic scan on common configuration files in the repository's root for potential hardcoded secrets. This is not a comprehensive security audit.
      </Alert>
      <Button variant="contained" onClick={handleScan} disabled={loading}>
        {loading ? <CircularProgress size={24} /> : 'Scan for Secrets'}
      </Button>
      
      {scanned && !loading && (
        <Box sx={{ mt: 2 }}>
          {secrets.length > 0 ? (
            <TableContainer component={Paper}>
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell>File</TableCell>
                    <TableCell>Secret Type</TableCell>
                    <TableCell>Masked Snippet</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {secrets.map((secret, index) => (
                    <TableRow key={index}>
                      <TableCell>{secret.file}</TableCell>
                      <TableCell>{secret.type}</TableCell>
                      <TableCell><code>{secret.snippet}</code></TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          ) : (
            <Typography sx={{ mt: 2 }}>No secrets found in common configuration files.</Typography>
          )}
        </Box>
      )}
    </Paper>
  );
};

export default SecretDetection;
