import React, { useEffect, useState } from 'react';
import { Paper, Typography, Box, Chip, CircularProgress } from '@mui/material';
import { getRepositoryContent } from '../../services/api';

interface TechStackProps {
  owner: string;
  repoName: string;
}

const techDetectionRules: { [key: string]: string[] } = {
  JavaScript: ['package.json', '.js'],
  TypeScript: ['tsconfig.json', '.ts'],
  Python: ['requirements.txt', 'pyproject.toml', '.py'],
  Java: ['pom.xml', 'build.gradle', '.java'],
  Go: ['go.mod', '.go'],
  Ruby: ['Gemfile', '.rb'],
  PHP: ['composer.json', '.php'],
  'C#': ['.csproj', '.cs'],
  'C++': ['.cpp', '.hpp'],
  Rust: ['Cargo.toml', '.rs'],
  Docker: ['Dockerfile'],
};

const TechStack: React.FC<TechStackProps> = ({ owner, repoName }) => {
  const [tech, setTech] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const detectTech = async () => {
      setLoading(true);
      try {
        const content = await getRepositoryContent(owner, repoName);
        const fileNames = content.map((item: any) => item.name);
        
        const detected: Set<string> = new Set();
        fileNames.forEach((name: string) => {
          for (const techName in techDetectionRules) {
            if (techDetectionRules[techName].some(rule => name.includes(rule))) {
              detected.add(techName);
            }
          }
        });
        setTech(Array.from(detected));
      } catch (error) {
        console.error("Error detecting technology stack:", error);
      } finally {
        setLoading(false);
      }
    };

    detectTech();
  }, [owner, repoName]);

  return (
    <Paper sx={{ p: 2, height: '100%' }}>
      <Typography variant="h6" gutterBottom>Technology Stack</Typography>
      {loading ? <CircularProgress size={24} /> : (
        <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
          {tech.length > 0 ? tech.map(t => <Chip key={t} label={t} color="primary" />) : <Typography>Could not determine stack.</Typography>}
        </Box>
      )}
    </Paper>
  );
};

export default TechStack;
