import React, { useState } from 'react';
import { Box, TextField, Button, Typography, Paper, Alert } from '@mui/material';

const Settings: React.FC = () => {
  const [token, setToken] = useState<string>(sessionStorage.getItem('github_pat') || '');

  const handleSave = () => {
    sessionStorage.setItem('github_pat', token);
    alert('Token saved for this session.');
  };

  return (
    <Paper sx={{ p: 2, mt: 2 }}>
      <Typography variant="h6" gutterBottom>
        API Settings
      </Typography>
      <Alert severity="warning" sx={{ mb: 2 }}>
        Provide a GitHub Personal Access Token to increase API rate limits (from 60 to 5000 requests/hour). The token is stored in your browser's session storage and is not sent to any server besides GitHub.
      </Alert>
      <Box sx={{ display: 'flex', alignItems: 'center' }}>
        <TextField
          label="GitHub Personal Access Token"
          type="password"
          variant="outlined"
          fullWidth
          value={token}
          onChange={(e) => setToken(e.target.value)}
          sx={{ mr: 1 }}
        />
        <Button variant="contained" onClick={handleSave}>
          Save
        </Button>
      </Box>
    </Paper>
  );
};

export default Settings;
