import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { Container, Typography, Box, Paper, CircularProgress, Alert, Grid, Chip } from '@mui/material';
import { getRepository } from '../services/api';
import { GitHubRepo } from '../types/github';
import StarIcon from '@mui/icons-material/Star';
import ForkRightIcon from '@mui/icons-material/ForkRight';
import BugReportIcon from '@mui/icons-material/BugReport';
import VisibilityIcon from '@mui/icons-material/Visibility';
import HealthScore from '../components/analysis/HealthScore';
import TechStack from '../components/analysis/TechStack';
import SecretDetection from '../components/analysis/SecretDetection';

const RepositoryPage: React.FC = () => {
  const { owner, repoName } = useParams<{ owner: string; repoName: string }>();
  const [repo, setRepo] = useState<GitHubRepo | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchRepo = async () => {
      if (!owner || !repoName) return;
      setLoading(true);
      try {
        const data = await getRepository(owner, repoName);
        setRepo(data);
      } catch (err: any) {
        setError(err.message || 'An error occurred');
      } finally {
        setLoading(false);
      }
    };
    fetchRepo();
  }, [owner, repoName]);

  if (loading) {
    return <CircularProgress />;
  }

  if (error) {
    return <Alert severity="error">{error}</Alert>;
  }

  if (!repo) {
    return <Alert severity="info">Repository not found.</Alert>;
  }

  return (
    <Container maxWidth="lg" sx={{ mt: 4 }}>
      <Paper sx={{ p: 3 }}>
        <Typography variant="h3" component="h1" gutterBottom>
          {repo.full_name}
        </Typography>
        <Typography variant="body1" color="text.secondary" gutterBottom>
          {repo.description}
        </Typography>
        <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2, mt: 2, mb: 3 }}>
            <Chip icon={<StarIcon />} label={`${repo.stargazers_count} Stars`} />
            <Chip icon={<VisibilityIcon />} label={`${repo.watchers_count} Watchers`} />
            <Chip icon={<ForkRightIcon />} label={`${repo.forks_count} Forks`} />
            <Chip icon={<BugReportIcon />} label={`${repo.open_issues_count} Open Issues`} />
            {repo.license && <Chip label={`License: ${repo.license.name}`} variant="outlined" />}
        </Box>
        <Grid container spacing={3}>
          <Grid item xs={12} md={6}>
            <HealthScore repo={repo} />
          </Grid>
          <Grid item xs={12} md={6}>
            <TechStack owner={owner!} repoName={repoName!} />
          </Grid>
          <Grid item xs={12}>
            <SecretDetection owner={owner!} repoName={repoName!} />
          </Grid>
        </Grid>
      </Paper>
    </Container>
  );
};

export default RepositoryPage;
