import React, { useState } from 'react';
import { Box, Container, Typography, Button, Collapse } from '@mui/material';
import SearchBar from '../components/SearchBar';
import Settings from '../components/Settings';
import { GitHubRepo } from '../types/github';
import SearchResults from '../components/SearchResults';
import { searchRepositories } from '../services/api';

const HomePage: React.FC = () => {
  const [showSettings, setShowSettings] = useState(false);
  const [results, setResults] = useState<GitHubRepo[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSearch = async (query: string) => {
    if (!query) return;
    setLoading(true);
    setError(null);
    try {
      const response = await searchRepositories(query);
      setResults(response.items);
    } catch (err: any) {
      setError(err.message || 'An error occurred while searching.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="lg">
      <Box sx={{ my: 4 }}>
        <Box sx={{ textAlign: 'center' }}>
          <Typography variant="h2" component="h1" gutterBottom>
            GitHub OSINT
          </Typography>
          <Typography variant="h5" component="h2" color="text.secondary" gutterBottom>
            Vulnerability Discovery Platform
          </Typography>
        </Box>
        <Box sx={{ width: '100%', mt: 4 }}>
          <SearchBar onSearch={handleSearch} />
          <Box sx={{ display: 'flex', justifyContent: 'flex-end', mt: 1 }}>
            <Button onClick={() => setShowSettings(!showSettings)}>
              {showSettings ? 'Hide Settings' : 'API Settings'}
            </Button>
          </Box>
          <Collapse in={showSettings}>
            <Settings />
          </Collapse>
        </Box>
        <Box sx={{ mt: 4 }}>
          {loading && <Typography>Loading...</Typography>}
          {error && <Typography color="error">{error}</Typography>}
          {!loading && !error && <SearchResults repositories={results} />}
        </Box>
      </Box>
    </Container>
  );
};

export default HomePage;
